def findMinArrowShots(balloons: list[list[int]]) -> int:
    if not balloons:
        return 0

    balloons.sort(key=lambda x: x[1])

    arrows = 0
    last_shoot_point = float('-inf')

    for start, end in balloons:
        if start > last_shoot_point:
            arrows += 1
            last_shoot_point = end

    return arrows
